public int makeChocolate(int small, int big, int goal) {
    int totalBigBars = big * 5;
    int remainingChocolate = goal - totalBigBars;

    if (remainingChocolate < 0) {
        return -1;
    } else if (remainingChocolate <= small) {
        return remainingChocolate;
    } else {
        return -1;
    }
}

