public int roundSum(int a, int b, int c) {
    return round10(a) + round10(b) + round10(c);
}

public int round10(int num) {
    int rightmostDigit = Math.abs(num) % 10;
    if (rightmostDigit >= 5) {
        num += 10 - rightmostDigit;
    } else {
        num -= rightmostDigit;
    }
    return num;
}

