public boolean xyBalance(String str) {
    int yCount = 0;
    boolean hasY = false;
    for (int i = 0; i < str.length(); i++) {
        char c = str.charAt(i);
        if (c == 'x') {
            if (hasY) {
                yCount--;
                if (yCount < 0) {
                    hasY = false;
                    yCount = 0;
                }
            }
        } else if (c == 'y') {
            yCount++;
            hasY = true;
        } else {
            return false;
        }
    }
    return hasY && yCount >= 0;
}

