public int[] seriesUp(int n) {
    int[] arr = new int[n * (n + 1) / 2];
    generate(arr, n, 1, 0);
    return arr;
}

private void generate(int[] arr, int n, int value, int index) {
    if (n < 1) {
        return;
    }
    arr[index] = value;
    generate(arr, n - 1, value + 1, index + n);
    generate(arr, n - 1, value, index + 1);
}

