public String repeatEnd(String str, int n) {
    if (n > 0 && n <= str.length()) {
        String end = str.substring(str.length() - n);
        StringBuilder repeatedEnd = new StringBuilder();

        for (int i = 0; i < n; i++) {
            repeatedEnd.append(end);
        }

        return repeatedEnd.toString();
    } else {
        return "";
    }
}

