public boolean xyBalance(String str) {
    int xPos = str.length();
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'x') {
            xPos = i;
        } else if (str.charAt(i) == 'y' && i > xPos) {
            xPos = str.length();
        }
    }
    return xPos == str.length();
}

public int[] shiftLeft(int[] nums) {
    int N = nums.length;
    if (N == 0 || N == 1) return nums;
    int temp = nums[0];
    for (int i = 0; i < N - 1; i++) {
        nums[i] = nums[i + 1];
    }
    nums[N - 1] = temp;
    return nums;
}

public int[] fix45(int[] nums) {

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            for (int j = i + 1; j < nums.length; j++) {
                if (nums[j] == 5) {
                    int temp = nums[j];
                    nums[j] = nums[i + 1];
                    nums[i + 1] = temp;
                    break;
                }
            }
        }
    }
    return nums;
}

public int[] fix45(int[] nums) {
    int i = 0, j = 0;
    while (j < nums.length) {
        if (nums[j] == 5) {
            j++;
        } else if (nums[j] == 4) {
            while (nums[i] != 5) {
                i++;
            }
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
            i++;
            j++;
        } else {
            j++;
        }
    }
    return nums;
}

