public String zipZap(String str) {
    StringBuilder sb = new StringBuilder();
    char[] chars = str.toCharArray();
    for (int i = 0; i < chars.length - 1; i++) {
        if (chars[i] == 'z' && chars[i + 1] == 'p') {
            sb.append('z');
            sb.append(chars[i + 1]);
            i++;
        } else {
            sb.append(chars[i]);
        }
    }
    sb.append(chars[chars.length - 1]);
    return sb.toString();
}

