    for (int i = 0; i < str.length() - 2; i++) {
        if (str.charAt(i) == 'z' && str.charAt(i + 2) == 'p') {
            if (str.charAt(i + 1) != 'o') {
                resultStr.append(str.charAt(i));
                resultStr.append(str.charAt(i + 2));
                i++;
            } else {
                resultStr.append(str.charAt(i));
            }
        } else {
            resultStr.append(str.charAt(i));
        }
    }
    if (str.length() > 2) {
        resultStr.append(str.charAt(str.length() - 1));
    }
    return resultStr.toString();
}

