public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0;
    int right = 0;
    while (right < n) {
        if (nums[right] == 4) {
            while (left < n && nums[left] != 5) {
                left++;
            }
            if (left < n) {
                int temp = nums[left];
                nums[left] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
                left++;
            } else {
                return nums;
            }
        } else {
            right++;
        }
    }
    return nums;
}

public int[] tenRun(int[] nums) {
    for(int i=0; i<nums.length; i++) {
        if(nums[i] % 10 == 0) {
            for(int j=i; j<nums.length; j++) {
                if(nums[j] % 10 == 0 && nums[j] != nums[i]) {
                    break;
                }
                nums[j] = nums[i];
            }
        }
    }
    return nums;
}

public int[] tenRun(int[] nums) {
