Code:
public int centeredAverage(int[] nums) {
    int min = nums[0];
    int max = nums[0];
    int sum = 0;
    int count = 0;

    for (int i : nums) {
        min = Math.min(min, i);
        max = Math.max(max, i);
        sum += i;
        count++;
    }

    sum = sum - min - max;
    count -= 2;

    return sum / count;
}

