def count_clumps(nums):
    count = 0
    i = 1
    while i < len(nums):
        if nums[i] == nums[i-1]:
            while i < len(nums) and nums[i] == nums[i-1]:
                i += 1
            count += 1
        else:
            i += 1
    return count

public int countClumps(int[] nums) {
    int count = 0;
    int i = 1;
    while (i < nums.length) {
        if (nums[i] == nums[i-1]) {
            while (i < nums.length && nums[i] == nums[i-1]) {
                i++;
            }
            count++;
        } else {
            i++;
        }
    }
    return count;
}

