Code:
public int[] fix45(int[] nums) {
    int i = 0, j = 0;

    while (j < nums.length) {
        if (nums[j] != 4) {
            j++;
            continue;
        }

        while (i < j && nums[i] != 5) {
            i++;
        }

        // Swap 5 with 4 if i < j and i < nums.length
        if (i < j && i < nums.length) {
            int temp = nums[j];
            nums[j] = nums[i];
            nums[i] = temp;
        }

        i = j + 1;
        j++;
    }

    return nums;
}

public int[] fix45(int[] nums) {
    List<Integer> fours = new ArrayList<>();
    int i = 0;
    int j = 0;
    while (i < nums.length) {
        if (nums[i] == 4) {
            fours.add(nums[i]);
            i++;
        } else if (nums[i] == 5) {
            nums[j] = nums[i];
            j++;
            nums[j] = 5;
            j++;
            i++;
        } else {
            nums[j] = nums[i];
            j++;
            i++;
        }
    }
    for (int k = 0; k < fours.size(); k++) {
        nums[j] = fours.get(k);
        j++;
    }
    return nums;
}

