public boolean twoTwo(int[] nums) {
    int count = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            if (i > 0 && nums[i - 1] == 2) {
                count++;
            } else if (i < nums.length - 1 && nums[i + 1] == 2) {
                count++;
            }
        }
    }
    return count == nums.length;
}

