public int caughtSpeeding(int speed, boolean isBirthday) {
    int baseLimit = 60;
    int smallLimit = 80;
    int bigLimit = 81;

    if (isBirthday) {
        baseLimit += 5;
        smallLimit += 5;
    }

    if (speed <= baseLimit) {
        return 0;
    } else if (speed <= smallLimit) {
        return 1;
    } else {
        return 2;
    }
}

public int caughtSpeeding(int speed, boolean isBirthday) {
    int adjustedSpeed;

    if (isBirthday) {
        adjustedSpeed = speed - 5;
    } else {
        adjustedSpeed = speed;
    }

    if (adjustedSpeed <= 60) {
        return 0;
    } else if (adjustedSpeed > 60 && adjustedSpeed <= 80) {
        return 1;
    } else {
        return 2;
    }
}

