public int sum13(int[] nums) {
    int sum = 0;
    boolean isFollowingThirteen = false;

    for(int i = 0; i < nums.length; i++) {
        if(nums[i] == 13) {
            isFollowingThirteen = true;
        } else if(!isFollowingThirteen) {
            sum += nums[i];
        }
        isFollowingThirteen = false;
    }
    return sum;
}

