            res[j++] = nums[i];
            while (k < n && nums[k] != 5) {
                res[j++] = nums[k];
                k++;
            }
            res[j++] = nums[k++];
        } else {
            res[j++] = nums[i];
        }
        i++;
    }
    return res;
}

