public int[] seriesUp(int n) {
    ArrayList<Integer> list = new ArrayList<>();
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            list.add(j);
        }
    }
    int[] result = new int[n * (n + 1) / 2];
    for (int i = 0; i < list.size(); i++) {
        result[i] = list.get(i);
    }
    return result;
}

