public boolean twoTwo(int[] nums) {
    int count = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            count++;
            if (i > 0 && nums[i - 1] == 2) {
                count--;
            } else if (i < nums.length - 1 && nums[i + 1] == 2) {
                count--;
            }
        }
    }
    return count == 0;
}

public boolean canBalance(int[] nums) {
    int totalSum = 0;
    for(int i=0;i<nums.length;i++){
        totalSum += nums[i];
    }

    int leftSum = 0;
    for(int j=0; j<nums.length; j++){
        totalSum -= nums[j];
        if(totalSum == leftSum){
            return true;
        }
        leftSum += nums[j];
    }

    return false;
}

