Code:
public int[] shiftLeft(int[] nums) {
    if(nums.length == 0) {
        return new int[0];
    }

    int[] newArr = new int[nums.length];
    if(nums.length > 1) {
        newArr[0] = nums[nums.length - 1];
        for(int i = 1; i < nums.length; i++) {
            newArr[i] = nums[i - 1];
        }
    } else {
        newArr[0] = nums[0];
    }
    return newArr;
}

public int countClumps(int[] nums) {
    int count = 0;
    boolean isClump = false;

    for(int i = 0; i < nums.length - 1; i++) {
        if(nums[i] == nums[i + 1]) {
            if(!isClump) {
                count++;
                isClump = true;
            }
        } else {
            isClump = false;
        }
    }

    return count;
}

