    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            count++;
        } else {
            if (count >= 2) {
                clumps++;
            }
            count = 1;
        }
    }

    if (count >= 2) {
        clumps++;
    }

    return clumps;
}

