Code:
public int[] zeroMax(int[] nums) {
    for(int i = nums.length - 1; i >= 0; i--) {
        if(nums[i] == 0) {
            int largestOdd = findLargestOddToRight(nums, i);
            if(largestOdd != 0) {
                nums[i] = largestOdd;
            }
        }
    }
    return nums;
}

private int findLargestOddToRight(int[] nums, int startIndex) {
    int largestOdd = 0;
    for(int i = startIndex; i < nums.length; i++) {
        if(nums[i] % 2 != 0 && nums[i] > largestOdd) {
            largestOdd = nums[i];
        }
    }
    return largestOdd;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0;
    for (int right = 0; right < n; right++) {
        if (nums[right] == 5) {
            while (left < n && nums[left] != 4) {
                left++;
            }
            if (left != n) {
                int temp = nums[left + 1];
                nums[left + 1] = nums[right];
                nums[right] = temp;
            }
        }
    }
    return nums;
}

public int[] shiftLeft(int[] nums) {
    int[] shiftedArray = new int[nums.length];
    if(nums.length > 0){
        shiftedArray[0] = nums[nums.length - 1];
        for(int i=1; i < nums.length; i++){
            shiftedArray[i] = nums[i - 1];
        }
    }
    return shiftedArray;
}

public int[] shiftLeft(int[] nums) {
    if(nums.length > 0){
        int temp = nums[0];
        for(int i=0; i < nums.length-1; i++){
            nums[i] = nums[i+1];
        }
        nums[nums.length-1] = temp;
    }
    return nums;
}

