public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        big = goal / 5;
        if (big * 5 > goal) {
            big--;
        }
    }

    int remainingWeight = goal - big * 5;

    if (remainingWeight > small) {
        return -1;
    }

    return remainingWeight;
}

