public int countClumps(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    int clumpCount = 1; // First element is always a clump
    int currentValue = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == currentValue) {
            continue;
        } else {
            currentValue = nums[i];
            clumpCount++;
        }
    }

    return clumpCount;
}

