public int sum67(int[] nums) {
    int sum = 0;
    boolean addToSum = true;

    for (int num : nums) {
        if (num == 6) {
            addToSum = false;
        } else if (num == 7) {
            addToSum = true;
        } else {
            if (addToSum) {
                sum += num;
            }
        }
    }

    return sum;
}

public int loneSum(int a, int b, int c) {
    if (a == b && a == c)
        return 0;
    if (a == b)
        return c;
    if (a == c)
        return b;
    if (b == c)
        return a;
    return a + b + c;
}

