public int[] fix45(int[] nums) {
    int i = 0, j = 0;
    while (j < nums.length) {
        if (nums[j] == 5) {
            j++;
        } else if (nums[j] == 4) {
            while (nums[i] != 5) {
                i++;
            }
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
            i++;
            j++;
