public boolean xyBalance(String str) {
    int lastYPosition = str.length();
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            if (i < lastYPosition) {
                return false;
            }
        } else if (str.charAt(i) == 'y') {
            lastYPosition = i;
        }
    }
    return true;
}

