Code:
public boolean xyBalance(String str) {
    int xCount = 0;
    int yCount = 0;

    for(int i = 0; i < str.length(); i++) {
        if(str.charAt(i) == 'x') {
            xCount++;
        } else if(str.charAt(i) == 'y') {
            yCount++;
        }
    }

    if(xCount == 0) {
        return true;
    }

    if(yCount < xCount) {
        return false;
    }

    xCount = 0;
    yCount = 0;

    for(int i = str.length()-1; i >= 0; i--) {
        if(str.charAt(i) == 'x') {
            xCount++;
        } else if(str.charAt(i) == 'y') {
            yCount++;

            if(yCount >= xCount) {
                xCount = 0;
                yCount = 0;
            }
        }
    }

    return xCount == 0;
}

