public int[] tenRun(int[] nums) {
    for(int i=0; i<nums.length; i++) {
        if(nums[i] % 10 == 0) {
            for(int j=i; j<nums.length; j++) {
                if(nums[j] % 10 == 0 && nums[j] != nums[i]) {
                    break;
                }
                nums[j] = nums[i];
            }
        }
    }
    return nums;
}

public int[] tenRun(int[] nums) {
    int lastMultiple = -1;
    for(int i=0; i<nums.length; i++) {
        if(nums[i] % 10 == 0) {
            lastMultiple = nums[i];
        } else {
            nums[i] = lastMultiple;
        }
    }
    return nums;
}

