public int makeChocolate(int small, int big, int goal) {
    if (big * 5 >= goal) {
        int neededSmall = goal - (big * 5);
        if (neededSmall <= small) {
            return neededSmall;
        } else {
            return -1;
        }
    } else {
        int usedBig = goal / 5;
        if (usedBig >= big) {
            int remainingGoal = goal - (big * 5);
            int neededSmall = remainingGoal;
            if (neededSmall <= small) {
                return neededSmall;
            } else {
                return -1;
            }
        } else {
            int remainingGoal = goal - (usedBig * 5);
            int neededSmall = remainingGoal;
            if (neededSmall <= small) {
                return neededSmall;
            } else {
                return -1;
            }
        }
    }
}

