public boolean xyBalance(String str) {
    int xPos = str.length();
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'x') {
            xPos = i;
        } else if (str.charAt(i) == 'y' && i > xPos) {
            xPos = str.length();
        }
    }
    return xPos == str.length();
}

