public boolean xyBalance(String str) {
    int y_index = str.length();
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            if (y_index == str.length() || y_index <= i) {
                return false;
            }
        } else if (str.charAt(i) == 'y') {
            y_index = i;
        }
    }
    return true;
}

