    int wordStart = 0;
    int wordEnd = word.length();
    while (space != -1) {
        String substring = str.substring(0, space);
        if (substring.contains(word)) {
            result += substring;
        } else {
            result += "+".repeat(substring.length());
        }
        str = str.substring(space + 1);
        space = str.indexOf(" ");
