Code:
public int makeChocolate(int small, int big, int goal) {
    int total_big = big * 5;
    if (total_big >= goal) {
        goal -= total_big;
    } else {
        int needed_big_bars = (goal - total_big) / 5;
        if (needed_big_bars > big) {
            return -1;
        }
        goal -= needed_big_bars * 5;
    }
    if (goal <= small) {
        return goal;
    } else {
        return -1;
    }
}

