    int n = nums.length;
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            for (int j = i + 1; j < n; j++) {
                if (nums[j] == 5) {
                    int temp = nums[j];
                    nums[j] = nums[i+1];
                    nums[i+1] = temp;
                    break;
                }
            }
        }
    }
    return nums;
}

