public int countClumps(int[] nums) {
    int count = 0;
    int clumpStart = 0;
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[clumpStart]) {
            continue;
        } else {
            if (i - clumpStart >= 2) {
                count++;
            }
            clumpStart = i;
        }
    }
    if (nums.length - clumpStart >= 2) {
        count++;
    }
    return count;
}

