public int blackjack(int a, int b) {
    if (a<=0 || b<=0) {
        throw new IllegalArgumentException("Both arguments must be greater than zero");
    }
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        return (Math.abs(21 - a) < Math.abs(21 - b)) ? a : b;
    }
}

public String atFirst(String str) {
    if(str.isEmpty()) {
        return "@@";
    } else if(str.length() < 2) {
        return str + '@';
    } else {
        return str.substring(0, 2);
    }
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] output = new int[n];
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) {
            output[j++] = nums[i];
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            output[j++] = 5;
            output[j++] = 4;
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 5) {
            output[j++] = 5;
        }
    }
    return output;
}

