public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] res = new int[n];
    int i = 0, j = 0, k = 0;
    while (i < n) {
        if (nums[i] == 4) {
            res[j++] = nums[i];
            while (k < n && nums[k] != 5) {
                res[j++] = nums[k];
                k++;
            }
            res[j++] = nums[k++];
        } else {
            res[j++] = nums[i];
        }
        i++;
    }
    return res;
}

