public String alarmClock(int day, boolean vacation) {
    if(day < 0 || day > 6) {
        return "Invalid day";
    }

    if(vacation) {
        if(day == 6 || day == 0) {
            return "off";
        }
        else {
            return "10:00";
        }
    }
    else {
        if(day >= 1 && day <= 5) {
            return "7:00";
        }
        else {
            return "10:00";
        }
    }
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] ans = new int[n];
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) {
            ans[j++] = nums[i];
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            ans[j++] = 5;
            ans[j++] = 4;
        }
    }
    return ans;
}

