    int smallNeeded = goal % 5;

    while (bigNeeded > big) {
        bigNeeded--;
        smallNeeded += 5;
    }

    if (smallNeeded <= small && bigNeeded <= big) {
        return smallNeeded;
    }
    return -1;
}

