public int[] fix45(int[] nums) {
    int i = 0, j = 0;
    while (j < nums.length) {
        if (nums[j] == 5) {
            j++;
        } else {
            int tmp = nums[j];
            nums[j] = nums[i];
            nums[i] = tmp;
            i++;
            j++;
        }
    }
    int k = nums.length - 1;
    for (int p = nums.length - 1; p >= 0; p--) {
        if (nums[p] == 4) {
            while (nums[k] != 5) {
                k--;
            }
            int tmp = nums[k];
            nums[k] = nums[p];
            nums[p] = tmp;
            k--;
        }
    }
    return nums;
}

public static void main(String[] args) {
    int[] nums = {9, 4, 5, 9, 4, 9, 5, 4, 9};
    nums = fix45(nums);
    for (int num : nums) {
        System.out.print(num + " ");
    }
}

