public int[] fix45(int[] nums) {
    int i = 0, j = 0;

    while (j < nums.length) {
        if (nums[j] != 4) {
            j++;
            continue;
        }

        while (i < j && nums[i] != 5) {
            i++;
        }

        // Swap 5 with 4 if i < j and i < nums.length
        if (i < j && i < nums.length) {
            int temp = nums[j];
            nums[j] = nums[i];
            nums[i] = temp;
