public int sum13(int[] nums) {
    if (nums.length == 0) return 0;
    boolean unlucky = nums[0] == 13;
    int sum = unlucky ? 0 : nums[0];
    for (int i = unlucky ? 1 : 0; i < nums.length; i++) {
        if (nums[i] == 13) {
            unlucky = true;
        } else if (!unlucky) {
            sum += nums[i];
        }
    }
    return sum;
}

