public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int lastMultipleOfTen = -1;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            lastMultipleOfTen = nums[i];
        }
        if (lastMultipleOfTen != -1) {
            nums[i] = lastMultipleOfTen;
        }
    }
    return nums;
}

