Code:
public int greenTicket(int a, int b, int c) {
    int[] numbers = {a, b, c};
    int[] counts = new int[3];

    for (int number : numbers) {
        counts[number]++;
    }

    if (counts[0] == 3) {
        return 20;
    } else if (counts[0] == counts[1] || counts[0] == counts[2] || counts[1] == counts[2]) {
        return 10;
    } else {
        return 0;
    }
}

